16: // batch holds pending log streams waiting to be sent to Loki, and it's used
17: // to reduce the number of push requests to Loki aggregating multiple log streams
18: // and entries in a single batch request. In case of multi-tenant Promtail, log
19: // streams for each tenant are stored in a dedicated batch.
20: type batch struct {
21: 	streams   map[string]*logproto.Stream
22: 	bytes     int
23: 	createdAt time.Time
24: }
25: 
26: func newBatch(entries ...Entry) *batch {
27: 	b := &batch{
28: 		streams:   map[string]*logproto.Stream{},
29: 		bytes:     0,
30: 		createdAt: time.Now(),
31: 	}
32: 
33: 	// Add entries to the batch
34: 	for _, entry := range entries {
35: 		b.add(entry)
36: 	}
37: 
38: 	return b
39: }
40: 
41: // add an entry to the batch
42: func (b *batch) add(entry Entry) {
43: 	b.bytes += len(entry.Line)
44: 
45: 	// Append the entry to an already existing stream (if any)
46: 	labels := labelsMapToString(entry.Labels, ReservedLabelTenantID)
47: 	if stream, ok := b.streams[labels]; ok {
48: 		stream.Entries = append(stream.Entries, entry.Entry)
49: 		return
50: 	}
51: 
52: 	// Add the entry as a new stream
53: 	b.streams[labels] = &logproto.Stream{
54: 		Labels:  labels,
55: 		Entries: []logproto.Entry{entry.Entry},
56: 	}
57: }
58: 
59: func labelsMapToString(ls model.LabelSet, without ...model.LabelName) string {
60: 	lstrs := make([]string, 0, len(ls))
61: Outer:
62: 	for l, v := range ls {
63: 		for _, w := range without {
64: 			if l == w {
65: 				continue Outer
66: 			}
67: 		}
68: 		lstrs = append(lstrs, fmt.Sprintf("%s=%q", l, v))
69: 	}
70: 
71: 	sort.Strings(lstrs)
72: 	return fmt.Sprintf("{%s}", strings.Join(lstrs, ", "))
73: }
74: 
75: // sizeBytesAfter returns the size of the batch after the input entry
76: // will be added to the batch itself
77: func (b *batch) sizeBytesAfter(entry Entry) int {
78: 	return b.bytes + len(entry.Line)
79: }
80: 
81: // age of the batch since its creation
82: func (b *batch) age() time.Duration {
83: 	return time.Since(b.createdAt)
84: }
85: 
86: // encode the batch as snappy-compressed push request, and returns
87: // the encoded bytes and the number of encoded entries
88: func (b *batch) encode() ([]byte, int, error) {
89: 	req, entriesCount := b.createPushRequest()
90: 	buf, err := proto.Marshal(req)
91: 	if err != nil {
92: 		return nil, 0, err
93: 	}
94: 	buf = snappy.Encode(nil, buf)
95: 	return buf, entriesCount, nil
96: }
97: 
98: // creates push request and returns it, together with number of entries
99: func (b *batch) createPushRequest() (*logproto.PushRequest, int) {
100: 	req := logproto.PushRequest{
101: 		Streams: make([]logproto.Stream, 0, len(b.streams)),
102: 	}
103: 
104: 	entriesCount := 0
105: 	for _, stream := range b.streams {
106: 		req.Streams = append(req.Streams, *stream)
107: 		entriesCount += len(stream.Entries)
108: 	}
109: 	return &req, entriesCount
110: }
